package org.example;

import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

import org.example.cleaning.RecordCleaner;
import org.example.model.PatientRecord;
import org.example.util.JsonFileService;
import org.example.validation.JsonPreValidator;
import org.example.validation.RecordValidator;
import org.example.validation.ValidationIssue;

public class App {
    public String getGreeting() {
        return "Welcome to the Record Validator App!";
    }

    public static void main(String[] args) throws Exception {
        int totalIssues = 0; 
        System.out.println();
        System.out.println(new App().getGreeting());
        String resourcePath = "sample-data/patients-1.json"; 

        if (args.length > 0) {
            resourcePath = args[0]; 
        }
        try {
            JsonFileService fileService = new JsonFileService(); 
            // TO DO Replace with resourcePath after testing: 
            String json = fileService.readResourceAsString("sample-data/patients-2-invalid.json"); 
            List<ValidationIssue> preValidatonIssues = JsonPreValidator.validateJsonTypes(json); 
            if (!preValidatonIssues.isEmpty()){
                System.out.println();
                System.err.println("Pre-validation errors found:");
                for (ValidationIssue issue : preValidatonIssues) {
                    System.err.println(issue);
                    totalIssues++; 
                }
                System.err.println();
                System.err.println("--------");
                System.err.println();
            }

            List<PatientRecord>  records = fileService.loadRecords(resourcePath); 
            List<PatientRecord> cleanedRecords = new ArrayList<>(); 

            RecordValidator validator = new RecordValidator(); 
            RecordCleaner cleaner = new RecordCleaner(); 

            // validate, clean, print results. 
            System.out.println("Records loaded: " + records.size());

            
            for (PatientRecord record : records) {
                System.out.println();
                System.out.println("--------");
                System.out.println();

                PatientRecord cleanedRecord = cleaner.clean(record); 
                List<ValidationIssue> issues = validator.validate(record, cleanedRecord); 
                cleanedRecords.add(cleanedRecord);
                System.out.println("Initial: " + record.toString());
                System.out.println("Cleaned: " + cleanedRecord.toString());
                if (!issues.isEmpty()) {
                    totalIssues += issues.size(); 
                    System.out.println("Issues found in " + cleanedRecord.patientId + ":");
                    for (ValidationIssue issue : issues) {
                        System.out.println(issue);
                    } 
                } else {
                        System.out.println("No issues found in " + record.patientId);
                    }

            }
            System.out.println("\n");
            System.out.println("SUMMARY");
            System.out.println("--------");
            System.out.println("Found a total of " + totalIssues + " issues in " + records.size() + " records.");

            fileService.saveRecords(cleanedRecords, "cleaned-output.json");
            System.out.println("Cleaned JSON exported to cleaned-output.json");
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
            System.err.println("Make sure the file exists in app/src/main/resources/" + resourcePath);
            System.exit(1); // close with error 
        }
        System.out.println("Validation complete. Exiting.");
    }
}
